import{_ as a,o as t,c as r,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Partner Capabilities Update","description":"","frontmatter":{"title":"Partner Capabilities Update","slug":"partner-capabilities-update"},"headers":[],"relativePath":"account-hub/partner-capabilities-update.md","filePath":"account-hub/partner-capabilities-update.md"}'),o={name:"account-hub/partner-capabilities-update.md"};function s(i,e,l,d,p,h){return t(),r("div",null,[...e[0]||(e[0]=[n('<p>July has been a busy month for Branch Partners! We&#39;ve made many (some new) improvements and updates to Movable Ink, MoEngage, Pinterest, and Oracle Responsys. More information here! 🎁</p><h2 id="movable-ink" tabindex="-1">Movable Ink <a class="header-anchor" href="#movable-ink" aria-label="Permalink to &quot;Movable Ink&quot;">​</a></h2><p>A <a href="./movable-ink.html">Movable Ink</a> Data Integration has been created! You can now send data captured through the Branch SDK to Movable Ink, providing up-to-date insights into user actions and preferences. Branch can now send the following events to Movable Ink:</p><table tabindex="0"><thead><tr><th>App Events</th><th>Commerce Events</th><th>Content Events</th><th>Custom Events</th></tr></thead><tbody><tr><td>- Install - Open</td><td>- Add to Cart - Purchase</td><td>- View Item - View Items - Search</td><td>- Custom Event</td></tr></tbody></table><hr><h2 id="moengage" tabindex="-1">MoEngage <a class="header-anchor" href="#moengage" aria-label="Permalink to &quot;MoEngage&quot;">​</a></h2><p><a href="./moengage.html">MoEngage</a> has been upgraded to forward additional events with more metadata. Updated metadata includes:</p><ul><li>Customer ID</li><li>Device ID</li><li>Event Name</li><li>Platform (OS)</li><li>App Version</li><li>Timestamp</li><li>Attributes (JSON)</li></ul><hr><h2 id="pinterest" tabindex="-1">Pinterest <a class="header-anchor" href="#pinterest" aria-label="Permalink to &quot;Pinterest&quot;">​</a></h2><p><a href="./pinterest.html">Pinterest</a> has released Version 5 of their <a href="https://developers.pinterest.com/docs/conversions/updated/" target="_blank" rel="noreferrer">Conversions API</a>, and Branch now supports it! If you already had Pinterest enabled for your Branch account and just need to enable support for Conversions, you just need to <a href="./reset-my-ad-partners-settings.html">reset your partner settings</a> for Pinterest with your <strong>Ad Account Id</strong> and <strong>Conversion Token</strong>.</p><hr><h2 id="oracle-responsys" tabindex="-1">Oracle Responsys <a class="header-anchor" href="#oracle-responsys" aria-label="Permalink to &quot;Oracle Responsys&quot;">​</a></h2><p><a href="./oracle-responsys.html">Oracle Responsys</a> has been one of Branch&#39;s popular email service providers to integrate Branch Email with. Because of its popularity, there was a need to revamp our partner documentation, so the entire guide has been updated based on how current customers use Responsys today.</p><p>A few notable updates:</p><ul><li>Updated page structure to have better step-by-step instructions and general cleanup.</li><li>Added more information on <a href="./oracle-responsys.html#host-aasa-file">hosting AASA</a>.</li><li>Simplified <a href="./oracle-responsys.html#3-create-branch-links-for-your-emails">options</a> for using Branch in Responsys.</li><li>Added a <a href="./oracle-responsys.html#5-view-analytics">View Analytics</a> section.</li></ul>',16)])])}const m=a(o,[["render",s]]);export{u as __pageData,m as default};
